import { createAction, props } from '@ngrx/store';
import { Todo } from './todo.model';

// Good: events, grouped by source, described in the past tense.
export const enterTodosPage = createAction('[Todos Page] Entered');

export const addTodo = createAction(
  '[Todos Page] Add Todo Clicked',
  props<{ title: string }>()
);

export const toggleTodo = createAction(
  '[Todos List] Todo Toggled',
  props<{ id: string }>()
);

// API result actions live under their own source.
export const loadTodosSuccess = createAction(
  '[Todos API] Load Todos Succeeded',
  props<{ todos: Todo[] }>()
);

export const loadTodosFailure = createAction(
  '[Todos API] Load Todos Failed',
  props<{ error: string }>()
);

import { createReducer, on } from '@ngrx/store';
import * as TodosActions from './todos.actions';
import { Todo } from './todo.model';

export interface TodosState {
  items: Todo[];
  loading: boolean;
  error: string | null;
}

export const initialState: TodosState = {
  items: [],
  loading: false,
  error: null,
};

export const todosReducer = createReducer(
  initialState,
  on(TodosActions.enterTodosPage, (state) => ({
    ...state,
    loading: true,
    error: null,
  })),
  on(TodosActions.loadTodosSuccess, (state, { todos }) => ({
    ...state,
    items: todos,
    loading: false,
  })),
  on(TodosActions.loadTodosFailure, (state, { error }) => ({
    ...state,
    loading: false,
    error,
  })),
  // Immutable nested update: replace the toggled item, keep the rest by reference.
  on(TodosActions.toggleTodo, (state, { id }) => ({
    ...state,
    items: state.items.map((t) =>
      t.id === id ? { ...t, done: !t.done } : t
    ),
  }))
);

import { createFeatureSelector, createSelector } from '@ngrx/store';
import { TodosState } from './todos.reducer';

// Root selector for the feature slice.
export const selectTodosState =
  createFeatureSelector<TodosState>('todos');

// Field selectors compose off the feature selector.
export const selectAllTodos = createSelector(
  selectTodosState,
  (s) => s.items
);
export const selectLoading = createSelector(
  selectTodosState,
  (s) => s.loading
);

// Derived selector: memoized, so the filter runs only when items change.
export const selectActiveTodos = createSelector(
  selectAllTodos,
  (items) => items.filter((t) => !t.done)
);

// Composed selector combining multiple inputs.
export const selectTodoStats = createSelector(
  selectAllTodos,
  selectActiveTodos,
  (all, active) => ({
    total: all.length,
    active: active.length,
    done: all.length - active.length,
  })
);

// Parameterized selector via a factory — one memoized instance per id.
export const selectTodoById = (id: string) =>
  createSelector(selectAllTodos, (items) =>
    items.find((t) => t.id === id)
  );

