import { inject } from '@angular/core';
import { Actions, createEffect, ofType } from '@ngrx/effects';
import { catchError, map, of, switchMap } from 'rxjs';
import { TodosService } from './todos.service';
import * as TodosActions from './todos.actions';

export const loadTodos$ = createEffect(
  (actions$ = inject(Actions), api = inject(TodosService)) =>
    actions$.pipe(
      ofType(TodosActions.enterTodosPage),
      switchMap(() =>
        api.getAll().pipe(
          map((todos) => TodosActions.loadTodosSuccess({ todos })),
          // catchError INSIDE the inner pipe: only this request fails,
          // the outer effect stream stays alive for the next action.
          catchError((err) =>
            of(TodosActions.loadTodosFailure({ error: err.message }))
          )
        )
      )
    ),
  { functional: true }
);

import { createEntityAdapter, EntityState } from '@ngrx/entity';
import { createReducer, on } from '@ngrx/store';
import { Todo } from './todo.model';
import * as TodosActions from './todos.actions';

export interface TodosState extends EntityState<Todo> {
  loading: boolean;
  error: string | null;
}

export const adapter = createEntityAdapter<Todo>({
  selectId: (todo) => todo.id,
  sortComparer: (a, b) => a.createdAt.localeCompare(b.createdAt),
});

export const initialState: TodosState = adapter.getInitialState({
  loading: false,
  error: null,
});

export const todosReducer = createReducer(
  initialState,
  on(TodosActions.loadTodosSuccess, (state, { todos }) =>
    adapter.setAll(todos, { ...state, loading: false })
  ),
  on(TodosActions.addTodoSuccess, (state, { todo }) =>
    adapter.addOne(todo, state)
  ),
  on(TodosActions.toggleTodoSuccess, (state, { todo }) =>
    adapter.upsertOne(todo, state)
  ),
  on(TodosActions.deleteTodoSuccess, (state, { id }) =>
    adapter.removeOne(id, state)
  )
);

// Prebuilt, memoized selectors from the adapter.
import { createFeatureSelector, createSelector } from '@ngrx/store';
const selectState = createFeatureSelector<TodosState>('todos');
const { selectAll, selectEntities, selectTotal } = adapter.getSelectors();
export const selectAllTodos = createSelector(selectState, selectAll);
export const selectTodoEntities = createSelector(selectState, selectEntities);
export const selectTodoCount = createSelector(selectState, selectTotal);

