import { computed, inject } from '@angular/core';
import {
  signalStore, withState, withComputed, withMethods, patchState,
} from '@ngrx/signals';
import { withEntities, setAllEntities } from '@ngrx/signals/entities';
import { rxMethod } from '@ngrx/signals/rxjs-interop';
import { pipe, switchMap, tap } from 'rxjs';
import { tapResponse } from '@ngrx/operators';
import { Todo } from './todo.model';
import { TodosService } from './todos.service';

export const TodosStore = signalStore(
  { providedIn: 'root' },
  withState({ loading: false, error: null as string | null }),
  withEntities<Todo>(),
  withComputed((store) => ({
    activeCount: computed(
      () => store.entities().filter((t) => !t.done).length
    ),
  })),
  withMethods((store, api = inject(TodosService)) => ({
    loadAll: rxMethod<void>(
      pipe(
        tap(() => patchState(store, { loading: true, error: null })),
        switchMap(() =>
          api.getAll().pipe(
            tapResponse({
              next: (todos) =>
                patchState(store, setAllEntities(todos), { loading: false }),
              error: (e: Error) =>
                patchState(store, { error: e.message, loading: false }),
            })
          )
        )
      )
    ),
  }))
);

