import { inject } from '@angular/core';
import { Actions, createEffect, ofType } from '@ngrx/effects';
import { catchError, concatMap, map, of, switchMap, withLatestFrom } from 'rxjs';
import { Store } from '@ngrx/store';
import { TodosService } from './todos.service';
import { TodosActions, TodosApiActions } from './todos.actions';
import { selectTodoEntities } from './todos.selectors';

export const load$ = createEffect(
  (actions$ = inject(Actions), api = inject(TodosService)) =>
    actions$.pipe(
      ofType(TodosActions.pageEntered),
      switchMap(() =>
        api.getAll().pipe(
          map((todos) => TodosApiActions.loadSucceeded({ todos })),
          catchError((e) =>
            of(TodosApiActions.loadFailed({ error: e.message }))
          )
        )
      )
    ),
  { functional: true }
);

// concatMap: writes must persist in order and must not be cancelled.
export const add$ = createEffect(
  (actions$ = inject(Actions), api = inject(TodosService)) =>
    actions$.pipe(
      ofType(TodosActions.addClicked),
      concatMap(({ title }) =>
        api.create(title).pipe(
          map((todo) => TodosApiActions.addSucceeded({ todo })),
          catchError((e) =>
            of(TodosApiActions.writeFailed({ error: e.message }))
          )
        )
      )
    ),
  { functional: true }
);

export const toggle$ = createEffect(
  (
    actions$ = inject(Actions),
    api = inject(TodosService),
    store = inject(Store)
  ) =>
    actions$.pipe(
      ofType(TodosActions.toggleClicked),
      withLatestFrom(store.select(selectTodoEntities)),
      concatMap(([{ id }, entities]) => {
        const current = entities[id]!;
        return api.update({ ...current, done: !current.done }).pipe(
          map((todo) => TodosApiActions.toggleSucceeded({ todo })),
          catchError((e) =>
            of(TodosApiActions.writeFailed({ error: e.message }))
          )
        );
      })
    ),
  { functional: true }
);

