import { createFeatureSelector, createSelector } from '@ngrx/store';
import { Todo } from './todo.model';

export interface TodosState {
  items: Todo[];
  filter: 'all' | 'active' | 'done';
  search: string;
}

const selectState = createFeatureSelector<TodosState>('todos');
export const selectItems = createSelector(selectState, (s) => s.items);
export const selectFilter = createSelector(selectState, (s) => s.filter);
export const selectSearch = createSelector(selectState, (s) => s.search);

// Composed & memoized: recomputes only when items, filter, or search change.
export const selectFilteredTodos = createSelector(
  selectItems,
  selectFilter,
  selectSearch,
  (items, filter, search) => {
    const term = search.trim().toLowerCase();
    return items.filter((t) => {
      const matchesFilter =
        filter === 'all' ||
        (filter === 'active' && !t.done) ||
        (filter === 'done' && t.done);
      const matchesSearch =
        term === '' || t.title.toLowerCase().includes(term);
      return matchesFilter && matchesSearch;
    });
  }
);

// Parameterized selector via a factory: one memoized instance per id.
export const selectTodoById = (id: string) =>
  createSelector(selectItems, (items) => items.find((t) => t.id === id));

// Stats derived off the filtered result, still memoized.
export const selectFilteredCount = createSelector(
  selectFilteredTodos,
  (todos) => todos.length
);

import { computed, inject } from '@angular/core';
import {
  signalStore, withState, withComputed, withMethods, patchState,
} from '@ngrx/signals';
import { withEntities, setAllEntities } from '@ngrx/signals/entities';
import { rxMethod } from '@ngrx/signals/rxjs-interop';
import { tapResponse } from '@ngrx/operators';
import { pipe, switchMap, tap } from 'rxjs';
import { Todo } from './todo.model';
import { TodosService } from './todos.service';

export const TodosStore = signalStore(
  { providedIn: 'root' },
  withState({ loading: false, error: null as string | null }),
  withEntities<Todo>(),
  withComputed((store) => ({
    total: computed(() => store.entities().length),
    activeCount: computed(
      () => store.entities().filter((t) => !t.done).length
    ),
  })),
  withMethods((store, api = inject(TodosService)) => ({
    // switchMap preserves cancel-latest semantics from the original effect.
    load: rxMethod<void>(
      pipe(
        tap(() => patchState(store, { loading: true, error: null })),
        switchMap(() =>
          api.getAll().pipe(
            tapResponse({
              next: (todos) =>
                patchState(store, setAllEntities(todos), { loading: false }),
              error: (e: Error) =>
                patchState(store, { error: e.message, loading: false }),
            })
          )
        )
      )
    ),
    toggle(id: string) {
      const current = store.entities().find((t) => t.id === id);
      if (!current) return;
      patchState(store, setAllEntities(
        store.entities().map((t) =>
          t.id === id ? { ...t, done: !t.done } : t
        )
      ));
    },
  }))
);

